#include <bits/stdc++.h>
using namespace std;
using ll = long long;


void solve(long long N, std::vector<long long> A)
{
    auto minus_num_count = count_if(begin(A), end(A), [](ll a) { return a < 0; });
    auto min_abs_num = *min_element(begin(A), end(A), [](ll a, ll b) { return abs(a) < abs(b); });
    auto abs_total = accumulate(begin(A), end(A), 0LL, [](ll acc, ll n) { return acc + abs(n); });
    auto ans = abs_total - (((minus_num_count % 2) == 0) ? 0 : 2 * abs(min_abs_num));
    cout << ans << endl;
}

// Generated by 1.1.6 https://github.com/kyuridenamida/atcoder-tools  (tips: You use the default template now. You can remove this line by using your custom template)
// clang-format off
int main(){
    long long N;
    scanf("%lld",&N);
    std::vector<long long> A(N);
    for(int i = 0 ; i < N ; i++){
        scanf("%lld",&A[i]);
    }
    cin.tie(nullptr);
    cout.tie(nullptr);
	ios_base::sync_with_stdio(false);
    solve(N, std::move(A));
    return 0;
}
